external_knowledge:
- 'more prolific contributors' refers to contributors who have made over 100 contributions;
- 'participation in creating issues and pull requests' is measured by the total number of issues and pull requests they have created;
- 'effectiveness in contributions' is derived by dividing the number of contributions by the total issues in the repository, indicating how their contributions compare to the overall activity.

sql:
SELECT DISTINCT topic_name
FROM repository_topics
WHERE repo_id = 123;

SELECT topic_id, repo_id, topic_name
FROM repository_topics
LIMIT 10;

SELECT u.username, COUNT(c.comment_id) AS total_comments
FROM users u
JOIN comments c ON u.user_id = c.commented_by
WHERE (c.is_on_issue = 1 AND EXISTS (
    SELECT 1 FROM issues i WHERE i.issue_id = c.issue_id AND i.repo_id = c.repo_id
)) OR (c.is_on_issue = 0 AND EXISTS (
    SELECT 1 FROM pull_requests pr WHERE pr.pr_id = c.pr_id AND pr.repo_id = c.repo_id
))
GROUP BY u.username;

SELECT AVG(total_comments) AS average_comments_per_repo
FROM (
  SELECT COUNT(comment_id) AS total_comments
  FROM comments
  GROUP BY repo_id
);

SELECT contributor_name, total_commits
FROM contributors
WHERE total_commits = (SELECT MAX(total_commits) FROM contributors);

SELECT u.full_name, u.email
FROM users u
WHERE u.user_id IN (
    SELECT i.created_by
    FROM issues i
    WHERE i.is_open = 0
) AND u.user_id NOT IN (
    SELECT pr.created_by
    FROM pull_requests pr
);

SELECT contributor_name, contributions
FROM contributors
ORDER BY contributions DESC;

SELECT topic_name, COUNT(repo_id) AS number_of_repositories
FROM repository_topics
GROUP BY topic_name;
